package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.stream.JsonReader;
import com.google.gson.stream.JsonToken;
import com.google.gson.stream.JsonWriter;
import com.google.gson.internal.bind.TypeAdapters;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.io.IOException;
import java.lang.reflect.Method;

class GsonDoubleAdapterTest {

  private Gson gson;

  @BeforeEach
  void setUp() {
    gson = new Gson();
  }

  @Test
  void doubleAdapter_withSerializeSpecialFloatingPointValuesTrue_returnsTypeAdaptersDouble() throws Exception {
    Method doubleAdapterMethod = Gson.class.getDeclaredMethod("doubleAdapter", boolean.class);
    doubleAdapterMethod.setAccessible(true);

    @SuppressWarnings("unchecked")
    TypeAdapter<Number> adapter = (TypeAdapter<Number>) doubleAdapterMethod.invoke(gson, true);

    assertSame(TypeAdapters.DOUBLE, adapter);
  }

  @Test
  void doubleAdapter_withSerializeSpecialFloatingPointValuesFalse_readNull() throws Exception {
    Method doubleAdapterMethod = Gson.class.getDeclaredMethod("doubleAdapter", boolean.class);
    doubleAdapterMethod.setAccessible(true);

    @SuppressWarnings("unchecked")
    TypeAdapter<Number> adapter = (TypeAdapter<Number>) doubleAdapterMethod.invoke(gson, false);

    JsonReader jsonReader = mock(JsonReader.class);
    when(jsonReader.peek()).thenReturn(JsonToken.NULL);

    Number result = adapter.read(jsonReader);
    verify(jsonReader).nextNull();
    assertNull(result);
  }

  @Test
  void doubleAdapter_withSerializeSpecialFloatingPointValuesFalse_readDouble() throws Exception {
    Method doubleAdapterMethod = Gson.class.getDeclaredMethod("doubleAdapter", boolean.class);
    doubleAdapterMethod.setAccessible(true);

    @SuppressWarnings("unchecked")
    TypeAdapter<Number> adapter = (TypeAdapter<Number>) doubleAdapterMethod.invoke(gson, false);

    JsonReader jsonReader = mock(JsonReader.class);
    when(jsonReader.peek()).thenReturn(JsonToken.NUMBER);
    when(jsonReader.nextDouble()).thenReturn(42.5);

    Number result = adapter.read(jsonReader);
    assertEquals(42.5, result);
  }

  @Test
  void doubleAdapter_withSerializeSpecialFloatingPointValuesFalse_writeNull() throws Exception {
    Method doubleAdapterMethod = Gson.class.getDeclaredMethod("doubleAdapter", boolean.class);
    doubleAdapterMethod.setAccessible(true);

    @SuppressWarnings("unchecked")
    TypeAdapter<Number> adapter = (TypeAdapter<Number>) doubleAdapterMethod.invoke(gson, false);

    JsonWriter jsonWriter = mock(JsonWriter.class);

    adapter.write(jsonWriter, null);

    verify(jsonWriter).nullValue();
  }

  @Test
  void doubleAdapter_withSerializeSpecialFloatingPointValuesFalse_writeValidDouble() throws Exception {
    Method doubleAdapterMethod = Gson.class.getDeclaredMethod("doubleAdapter", boolean.class);
    doubleAdapterMethod.setAccessible(true);

    @SuppressWarnings("unchecked")
    TypeAdapter<Number> adapter = (TypeAdapter<Number>) doubleAdapterMethod.invoke(gson, false);

    JsonWriter jsonWriter = mock(JsonWriter.class);

    // Use a valid double value
    Double validDouble = 123.456;
    adapter.write(jsonWriter, validDouble);

    // Verify out.value called with the double value
    verify(jsonWriter).value(validDouble);
  }

  @Test
  void doubleAdapter_withSerializeSpecialFloatingPointValuesFalse_writeInvalidDouble_throws() throws Exception {
    Method doubleAdapterMethod = Gson.class.getDeclaredMethod("doubleAdapter", boolean.class);
    doubleAdapterMethod.setAccessible(true);

    @SuppressWarnings("unchecked")
    TypeAdapter<Number> adapter = (TypeAdapter<Number>) doubleAdapterMethod.invoke(gson, false);

    JsonWriter jsonWriter = mock(JsonWriter.class);

    // Use invalid double values: NaN and Infinity
    double[] invalidValues = { Double.NaN, Double.POSITIVE_INFINITY, Double.NEGATIVE_INFINITY };

    for (double invalidValue : invalidValues) {
      Number value = invalidValue; // Box primitive to Number
      IOException thrown = assertThrows(IOException.class, () -> adapter.write(jsonWriter, value));
      assertTrue(thrown.getMessage().contains("Invalid double:"));
    }
  }
}
